class Solution {
    public int peopleAwareOfSecret(int n, int delay, int forget) {
        long mod = 1000000007;
        long[] dp = new long[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            dp[i] = dp[i - 1];
            if (i >= delay && i % forget != 0 && i - delay >= 0) {
                dp[i] = (dp[i] + dp[i - delay]) % mod;
            }
        }
        return (int) dp[n];
    }
}
